pb_lines=3 function slow_cp_with_progress { progress_update 50 20 'copying file'; sleep $delay progress_update 50 25 'copying file'; sleep $delay progress_update 50 30 'copying file'; sleep $delay progress_update 50 35 'copying file'; sleep $delay progress_update 50 40 'copying file'; sleep $delay progress_update 50 45 'copying file'; sleep $delay cp "$1" "$2";
