} function clear_lines { local lines_to_clear local i lines_to_clear=$(($1 - 1)) # subtract 1 because bash loop range is inclusive if test "${lines_to_clear}" -ge 0 then for i in {1..${lines_to_clear}} do 1>&2 printf "\033[2K\r" # clear message line 1>&2 printf "\033[1A" # move cursor up one line done fi
} function progress_write { local progress_total local progress_done local progress_message local progress_remaining local printf_format progress_total=$1 progress_done=$2 progress_message="${3}" progress_remaining=$(($progress_total - $progress_done)) if test $progress_total -eq $progress_done then printf_format="\e[48;5;35m%${progress_done}s\e[48;5;35m%${progress_remaining}s\e[0m\n" # green else printf_format="\e[48;5;33m%${progress_done}s\e[48;5;18m%${progress_remaining}s\e[0m\n" # blue fi 1>&2 printf "$printf_format" ' ' ' ' 1>&2 printf "$progress_message" 1>&2 printf '\n'
} function progress_update { clear_lines $pb_lines # message line, progress bar line, extra line progress_write "$@"
} function informational_idempotent_cp { local src_hash; local dest_hash; progress_write 50 0 'hashing source file'; sleep $delay src_hash=$(hash_file "${src}") progress_update 50 5 'hashing destination file'; sleep $delay dest_hash=$(hash_file "${dest}") progress_update 50 10 'comparing hashes'; sleep $delay if ! test "${src_hash}" = "${dest_hash}" then progress_update 50 15 'copying file'; sleep $delay slow_cp_with_progress "$1" "$2" progress_update 50 50 '✅ file copied!' 1>&2 printf "\n" else progress_update 50 50 '✅ contents match, nothing to do!' 1>&2 printf "\n" fi;
} rm -f "${dest}" informational_idempotent_cp "${src}" "${dest}" delay=0.7
